SELECT C.groupCode , C.groupName , C.codeValue , C.codeName , C.orderNo FROM (
) C WHERE 1 = 1
AND C.groupCode = #{groupCode}
AND (C.groupCode ILIKE CONCAT('%', #{keyword}, '%') OR C.groupName ILIKE CONCAT('%', #{keyword}, '%') OR C.codeValue ILIKE CONCAT('%', #{keyword}, '%') OR C.codeName ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY C.groupCode ASC, C.orderNo ASC, C.codeValue ASC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM (
) C WHERE 1 = 1
AND C.groupCode = #{groupCode}
AND (C.groupCode ILIKE CONCAT('%', #{keyword}, '%') OR C.groupName ILIKE CONCAT('%', #{keyword}, '%') OR C.codeValue ILIKE CONCAT('%', #{keyword}, '%') OR C.codeName ILIKE CONCAT('%', #{keyword}, '%'))
